INSERT INTO offmarket.business_signals (business_id,layer,signal_key,direction,evidence,source,source_url,observed_at) VALUES
('4d4f7b62-b333-5361-960d-75ad288b96b5', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 42 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://travis-electricservices.com/', '2026-05-15'),('88afff32-730d-596d-8f83-f90a9615cd2f', 3, 'successor_check_live_fetch', 'negative', '2nd-gen Mather family on team + commercial/industrial union shop, not residential service. Wrong vertical.', 'live_website_fetch', 'https://matherelectric.com/', '2026-05-15'),('88afff32-730d-596d-8f83-f90a9615cd2f', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 24 yrs in business per company website/search. Owner age estimate 52 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://matherelectric.com/', '2026-05-15'),('88afff32-730d-596d-8f83-f90a9615cd2f', 3, 'no_ev_charger_service', 'positive', 'Site does not list EV-charger install services. In 2026 TX metros, this is a coasting tell — every healthy residential electrical shop offers EV-charger install.', 'live_website_fetch', 'https://matherelectric.com/', '2026-05-15'),('88afff32-730d-596d-8f83-f90a9615cd2f', 3, 'no_online_booking', 'positive', 'Site does not offer online booking integration (no Housecall Pro / ServiceTitan / Yapi visible).', 'live_website_fetch', 'https://matherelectric.com/', '2026-05-15'),('2578cb92-0fa7-5c5b-9495-0c63f9034dfe', 3, 'successor_check_live_fetch', 'negative', '3rd generation Puckett family explicitly named. Internal succession in place.', 'web_search_synthesis', 'https://www.puckettelectric.com/', '2026-05-15'),('2578cb92-0fa7-5c5b-9495-0c63f9034dfe', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 50 yrs in business per company website/search. Owner age estimate 72 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://www.puckettelectric.com/', '2026-05-15'),('ffe7d07c-e3e7-52e3-9e5e